import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import API from '../services/axios';

function EventDetails() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [event, setEvent] = useState(null);
  const [loading, setLoading] = useState(true);
  const [tickets, setTickets] = useState(1);
  const [booking, setBooking] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  useEffect(() => {
    const fetchEvent = async () => {
      try {
        const res = await API.get(`/events/${id}`);
        setEvent(res.data.event);
      } catch { setError('Event not found'); }
      finally { setLoading(false); }
    };
    fetchEvent();
  }, [id]);

  const handleBook = async () => {
    setError(''); setBooking(true);
    try {
      await API.post('/bookings', { eventId: id, numberOfTickets: tickets });
      setSuccess('🎉 Booking successful! Redirecting...');
      setTimeout(() => navigate('/my-bookings'), 2000);
    } catch (err) {
      setError(err.response?.data?.message || 'Booking failed');
    } finally { setBooking(false); }
  };

  if (loading) return (
    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: '60vh' }}>
      <div style={{ textAlign: 'center', color: 'white' }}>
        <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>🎉</div>
        <p>Loading event...</p>
      </div>
    </div>
  );

  if (!event) return (
    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: '60vh' }}>
      <div style={{ textAlign: 'center', color: 'white' }}>
        <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>😕</div>
        <h2>Event Not Found</h2>
        <button onClick={() => navigate('/home')} style={{ marginTop: '1rem', background: '#7c3aed', color: 'white', border: 'none', padding: '10px 24px', borderRadius: '10px', cursor: 'pointer' }}>Go Home</button>
      </div>
    </div>
  );

  return (
    <div>
      {/* Hero */}
      <div style={{ position: 'relative', height: '350px' }}>
        <img src={event.image || 'https://via.placeholder.com/1200x350?text=Event'}
          alt={event.name} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
        <div style={{ position: 'absolute', inset: 0, background: 'linear-gradient(to top, rgba(0,0,0,0.8) 0%, transparent 60%)' }} />
        <div style={{ position: 'absolute', bottom: '2rem', left: '2rem', color: 'white' }}>
          <span style={{ background: 'linear-gradient(135deg, #7c3aed, #a78bfa)', padding: '4px 14px', borderRadius: '20px', fontSize: '0.75rem', fontWeight: '700', marginBottom: '10px', display: 'inline-block' }}>{event.category}</span>
          <h1 style={{ fontSize: '2.5rem', fontWeight: '800', marginTop: '8px' }}>{event.name}</h1>
        </div>
      </div>

      <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '2rem', display: 'grid', gridTemplateColumns: '1fr 350px', gap: '2rem', alignItems: 'start' }}>
        {/* Info */}
        <div>
          <div style={{ background: 'rgba(255,255,255,0.07)', backdropFilter: 'blur(20px)', border: '1px solid rgba(255,255,255,0.12)', borderRadius: '16px', padding: '1.5rem', marginBottom: '1.5rem' }}>
            <h2 style={{ color: 'white', fontWeight: '700', marginBottom: '1rem' }}>About This Event</h2>
            <p style={{ color: 'rgba(255,255,255,0.7)', lineHeight: '1.7', fontSize: '0.9rem' }}>{event.description}</p>
          </div>
          <div style={{ background: 'rgba(255,255,255,0.07)', backdropFilter: 'blur(20px)', border: '1px solid rgba(255,255,255,0.12)', borderRadius: '16px', padding: '1.5rem' }}>
            <h2 style={{ color: 'white', fontWeight: '700', marginBottom: '1rem' }}>Event Details</h2>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
              {[
                { icon: '📅', label: 'Date', value: new Date(event.date).toLocaleDateString('en-IN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' }) },
                { icon: '🕐', label: 'Time', value: event.time },
                { icon: '📍', label: 'Venue', value: event.venue },
                { icon: '🎫', label: 'Seats Left', value: `${event.availableSeats} / ${event.totalSeats}` },
              ].map(item => (
                <div key={item.label} style={{ background: 'rgba(255,255,255,0.05)', borderRadius: '12px', padding: '1rem', display: 'flex', gap: '10px' }}>
                  <span style={{ fontSize: '1.3rem' }}>{item.icon}</span>
                  <div>
                    <p style={{ color: 'rgba(255,255,255,0.4)', fontSize: '0.72rem', marginBottom: '4px' }}>{item.label}</p>
                    <p style={{ color: 'white', fontWeight: '600', fontSize: '0.85rem' }}>{item.value}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Booking Card */}
        <div style={{ background: 'rgba(255,255,255,0.07)', backdropFilter: 'blur(20px)', border: '1px solid rgba(255,255,255,0.12)', borderRadius: '16px', padding: '1.5rem', position: 'sticky', top: '90px' }}>
          <p style={{ color: '#a78bfa', fontSize: '2rem', fontWeight: '800' }}>₹{event.price}</p>
          <p style={{ color: 'rgba(255,255,255,0.4)', fontSize: '0.8rem', marginBottom: '1.5rem' }}>per ticket</p>

          {error && <div style={{ background: '#fee2e2', color: '#991b1b', padding: '10px 14px', borderRadius: '10px', marginBottom: '1rem', fontSize: '0.8rem' }}>⚠️ {error}</div>}
          {success && <div style={{ background: '#d1fae5', color: '#065f46', padding: '10px 14px', borderRadius: '10px', marginBottom: '1rem', fontSize: '0.8rem' }}>{success}</div>}

          {event.availableSeats > 0 && event.status === 'upcoming' ? (
            <>
              <div style={{ marginBottom: '1rem' }}>
                <p style={{ color: 'rgba(255,255,255,0.7)', fontSize: '0.8rem', fontWeight: '600', marginBottom: '10px' }}>Number of Tickets</p>
                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                  <button onClick={() => setTickets(Math.max(1, tickets - 1))} style={{ width: '36px', height: '36px', borderRadius: '50%', background: 'rgba(255,255,255,0.1)', border: 'none', color: 'white', cursor: 'pointer', fontSize: '1.2rem', fontWeight: 'bold' }}>−</button>
                  <span style={{ color: 'white', fontWeight: '800', fontSize: '1.3rem', minWidth: '24px', textAlign: 'center' }}>{tickets}</span>
                  <button onClick={() => setTickets(Math.min(event.availableSeats, tickets + 1))} style={{ width: '36px', height: '36px', borderRadius: '50%', background: 'rgba(255,255,255,0.1)', border: 'none', color: 'white', cursor: 'pointer', fontSize: '1.2rem', fontWeight: 'bold' }}>+</button>
                </div>
              </div>
              <div style={{ background: 'rgba(255,255,255,0.05)', borderRadius: '10px', padding: '12px', marginBottom: '1rem' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', color: 'rgba(255,255,255,0.6)', fontSize: '0.8rem', marginBottom: '6px' }}>
                  <span>₹{event.price} × {tickets}</span><span>₹{event.price * tickets}</span>
                </div>
                <div style={{ display: 'flex', justifyContent: 'space-between', color: 'white', fontWeight: '700', borderTop: '1px solid rgba(255,255,255,0.1)', paddingTop: '8px' }}>
                  <span>Total</span><span style={{ color: '#a78bfa' }}>₹{event.price * tickets}</span>
                </div>
              </div>
              <button onClick={handleBook} disabled={booking} style={{
                width: '100%', background: 'linear-gradient(135deg, #7c3aed, #a78bfa)',
                color: 'white', border: 'none', padding: '14px', borderRadius: '12px',
                cursor: 'pointer', fontWeight: '700', fontSize: '0.9rem', opacity: booking ? 0.6 : 1
              }}>
                {booking ? '⏳ Booking...' : '🎟️ Book Now'}
              </button>
            </>
          ) : (
            <div style={{ textAlign: 'center', padding: '1.5rem' }}>
              <p style={{ color: 'rgba(255,255,255,0.4)' }}>Not available for booking</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
export default EventDetails;
